skeleton_by_intent.p2p_game:
(function(){
'use strict';
window.YM_S = window.YM_S || {};
let _ctx=null,_state='waiting';
window.YM_S['FILENAME'] = {
  name:'Game', icon:'🎮', category:'Games', description:'Desc',
  activate(ctx){ _ctx=ctx; ctx.onReceive((type,data,peerId)=>{ /* state machine transitions */ }); },
  deactivate(){ _ctx=null; _state='waiting'; },
  renderPanel(c){ c.innerHTML = '<div class="ym-card">'+_state+'</div>'; },
  broadcastData(){ return { state:_state }; },
};
})();

